using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Basil, Olive oil", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough.\n3. Spread crushed tomatoes.\n4. Add mozzarella slices.\n5. Bake 10-12 minutes.\n6. Top with fresh basil.", AverageRating = 4.5, RatingCount = 12 },
        new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti al dente.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, stir in egg mixture.\n6. Season with pepper.", AverageRating = 4.8, RatingCount = 20 },
        new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in spiced yogurt.\n2. Grill or broil chicken pieces.\n3. Sauté onion, garlic, ginger.\n4. Add tomato sauce and spices.\n5. Simmer, then add cream.\n6. Add chicken and serve with rice.", AverageRating = 4.7, RatingCount = 15 },
        new() { Id = 4, Title = "Pad Thai", Category = "Thai", Ingredients = "Rice noodles, Shrimp, Egg, Bean sprouts, Peanuts, Tamarind paste, Fish sauce, Lime", Steps = "1. Soak rice noodles.\n2. Stir-fry shrimp until pink.\n3. Push aside, scramble egg.\n4. Add noodles and sauce.\n5. Toss with bean sprouts.\n6. Serve with peanuts and lime.", AverageRating = 4.3, RatingCount = 8 },
        new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef.\n2. Add taco seasoning and water.\n3. Simmer until thickened.\n4. Warm taco shells.\n5. Fill with beef and toppings.\n6. Serve with salsa.", AverageRating = 4.1, RatingCount = 10 },
        new() { Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour", Steps = "1. Melt chocolate and butter.\n2. Whisk eggs and sugar.\n3. Fold in chocolate mixture.\n4. Add flour gently.\n5. Pour into greased ramekins.\n6. Bake 12 minutes at 425°F.", AverageRating = 4.9, RatingCount = 25 },
    };

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
        });
    }
}

@page "/recipes/{Category}"

@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@Category Recipes - RecipeHub</PageTitle>

<h1>@Category Recipes</h1>

@if (recipes is null || recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="recipe-list">
        @foreach (var recipe in recipes)
        {
            <div class="recipe-card">
                <h3><a href="/recipe/@recipe.Id">@recipe.Title</a></h3>
                <p>⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)</p>
            </div>
        }
    </div>
}

<p><a href="/">← Back to Categories</a></p>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    private IReadOnlyList<RecipeHub.Models.Recipe>? recipes;

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"

@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p><strong>Category:</strong> <a href="/recipes/@recipe.Category.ToLower()">@recipe.Category</a></p>

    <h2>Ingredients</h2>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h2>Steps</h2>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.Contains('.') ? step[(step.IndexOf('.') + 1)..].Trim() : step;
            <li>@text</li>
        }
    </ol>

    <h2>Rate This Recipe</h2>
    <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />
}

<p><a href="/">← Back to Home</a></p>

@code {
    [Parameter] public int Id { get; set; }
    private RecipeHub.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

@inject RecipeHub.Services.RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= displayRating ? "filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => displayRating = star"
              @onmouseout="() => displayRating = (int)Math.Round(CurrentRating)">
            ★
        </span>
    }
    <span class="rating-text">@CurrentRating / 5 (@RatingCount ratings)</span>
</div>

@if (submitted)
{
    <p class="rating-thanks">Thanks for rating!</p>
}

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int displayRating;
    private bool submitted;

    protected override void OnParametersSet()
    {
        displayRating = (int)Math.Round(CurrentRating);
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
            displayRating = stars;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer

@using RecipeHub.Models
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>

@if (successMessage is not null)
{
    <div class="alert-success">@successMessage</div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="submission.Title" class="form-control" />
            <ValidationMessage For="() => submission.Title" />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="submission.Category" class="form-control">
                <option value="">-- Select Category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Thai">Thai</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => submission.Category" />
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients (comma-separated)</label>
            <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="4" />
            <ValidationMessage For="() => submission.Ingredients" />
        </div>

        <div class="form-group">
            <label for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="6" />
            <ValidationMessage For="() => submission.Steps" />
        </div>

        <button type="submit" class="btn-submit">Submit Recipe</button>
    </EditForm>
}

<p><a href="/">← Back to Home</a></p>

@code {
    private RecipeSubmission submission = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(submission);
        successMessage = $"'{submission.Title}' submitted successfully!";
        submission = new();
    }
}

