    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="submission.Title" class="form-control" />
            <ValidationMessage For="() => submission.Title" />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="submission.Category" class="form-control">
                <option value="">-- Select Category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Thai">Thai</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => submission.Category" />
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients (comma-separated)</label>
            <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="4" />
            <ValidationMessage For="() => submission.Ingredients" />
        </div>

        <div class="form-group">
            <label for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="6" />
            <ValidationMessage For="() => submission.Steps" />
        </div>

        <button type="submit" class="btn-submit">Submit Recipe</button>
