using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Basil, Olive oil", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough.\n3. Spread crushed tomatoes.\n4. Add mozzarella slices.\n5. Bake 10-12 minutes.\n6. Top with fresh basil.", AverageRating = 4.5, RatingCount = 12 },
        new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti al dente.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, stir in egg mixture.\n6. Season with pepper.", AverageRating = 4.8, RatingCount = 20 },
        new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in spiced yogurt.\n2. Grill or broil chicken pieces.\n3. Sauté onion, garlic, ginger.\n4. Add tomato sauce and spices.\n5. Simmer, then add cream.\n6. Add chicken and serve with rice.", AverageRating = 4.7, RatingCount = 15 },
        new() { Id = 4, Title = "Pad Thai", Category = "Thai", Ingredients = "Rice noodles, Shrimp, Egg, Bean sprouts, Peanuts, Tamarind paste, Fish sauce, Lime", Steps = "1. Soak rice noodles.\n2. Stir-fry shrimp until pink.\n3. Push aside, scramble egg.\n4. Add noodles and sauce.\n5. Toss with bean sprouts.\n6. Serve with peanuts and lime.", AverageRating = 4.3, RatingCount = 8 },
        new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef.\n2. Add taco seasoning and water.\n3. Simmer until thickened.\n4. Warm taco shells.\n5. Fill with beef and toppings.\n6. Serve with salsa.", AverageRating = 4.1, RatingCount = 10 },
        new() { Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour", Steps = "1. Melt chocolate and butter.\n2. Whisk eggs and sugar.\n3. Fold in chocolate mixture.\n4. Add flour gently.\n5. Pour into greased ramekins.\n6. Bake 12 minutes at 425°F.", AverageRating = 4.9, RatingCount = 25 },
    };

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
        });
    }
}

